), resolved AS (
    SELECT
        p.id AS project_id,
        u.id AS user_id,
        rs.role_name
    FROM role_seed rs
    JOIN projects p ON p.name = rs.project_name AND p.deleted_at IS NULL
    JOIN users u ON u.email = rs.email AND u.deleted_at IS NULL
