INSERT INTO project_roles (user_id, project_id, role, created_at, updated_at, deleted_at)
SELECT
    r.user_id,
    r.project_id,
    r.role_name,
    NOW(),
    NOW(),
    NULL
FROM resolved r
WHERE NOT EXISTS (
    SELECT 1
    FROM project_roles pr
    WHERE pr.user_id = r.user_id
      AND pr.project_id = r.project_id
);

